mapper.select:
SELECT a.*, gvi.CONTENT AS ITEM_NAME_VI, gen.CONTENT AS ITEM_NAME_EN, gzh.CONTENT AS ITEM_NAME_ZH, gko.CONTENT AS ITEM_NAME_KO FROM AR_STA_FORMULAR a LEFT JOIN SY_GLOBAL_NAME gvi ON a.ITEM_NO = gvi.NO AND gvi.LANGUAGE = 'vi' LEFT JOIN SY_GLOBAL_NAME gen ON a.ITEM_NO = gen.NO AND gen.LANGUAGE = 'en' LEFT JOIN SY_GLOBAL_NAME gzh ON a.ITEM_NO = gzh.NO AND gzh.LANGUAGE = 'zh' LEFT JOIN SY_GLOBAL_NAME gko ON a.ITEM_NO = gko.NO AND gko.LANGUAGE = 'ko' WHERE a.CPNY_ID = #{cpnyId}
AND a.ITEM_NO = #{itemNo}
ORDER BY a.ORDERNO, a.FORMULAR_NO

mapper.insert:
INSERT INTO AR_STA_FORMULAR (
    FORMULAR_NO, ITEM_NO, CONDITION, FORMULAR, CPNY_ID, 
    ACTIVITY, ORDERNO, CREATE_DATE, CREATED_BY
) VALUES (
    #{formularNo}, #{itemNo}, #{condition}, #{formular}, #{cpnyId}, 
    #{activity}, #{orderno}, SYSDATE, #{adminID}
)

mapper.select:
SELECT DISTINCT A.ITEM_ID as "itemId",
       S2.CONTENT as "itemName",
       S1.CONTENT as "itemGroupName"
FROM AR_ITEM A
JOIN AR_ITEM_PARAM C ON A.ITEM_NO = C.ITEM_NO
LEFT JOIN SY_GLOBAL_NAME S1 ON A.ITEM_GROUP_CODE = S1.NO AND S1.LANGUAGE = #{lang}
LEFT JOIN SY_GLOBAL_NAME S2 ON A.ITEM_NO = S2.NO AND S2.LANGUAGE = #{lang}
WHERE C.CPNY_ID = #{cpnyId}
ORDER BY A.ITEM_ID
